const crypto = require('crypto');
const headerSig = msg.req?.headers?.['x-webhook-signature'] || '';
const raw = typeof msg.payload === 'string' ? msg.payload : JSON.stringify(msg.payload || {});
const secret = env.get('WEBHOOK_HMAC_SECRET') || '';
if (!secret) {
  msg.statusCode = 500;
  msg.payload = { ok: false, error: 'WEBHOOK_HMAC_SECRET ausente' };
  return [null, msg];
}
const expected = crypto.createHmac('sha256', secret).update(raw).digest('hex');
if (headerSig !== expected) {
  msg.statusCode = 401;
  msg.payload = { ok: false, error: 'assinatura_invalida' };
  return [null, msg];
}
return [msg, null];

const body = msg.payload || {};
const telefone = String(body.telefone || body.from || '').replace(/\D/g, '');
const texto = String(body.mensagem || body.text || '').trim();
const conversa = flow.get('ctx:' + telefone) || {};
msg.crm = {
  telefone,
  texto,
  nome: conversa.nome || body.nome || null,
  empresa: conversa.empresa || body.empresa || null,
  itens_interesse: conversa.itens_interesse || body.itens_interesse || null,
  estado: conversa.estado || body.estado || null,
  cidade: conversa.cidade || body.cidade || null
};
msg.topic = 'SELECT * FROM leads WHERE telefone = $1 LIMIT 1';
msg.payload = [telefone];
return msg;

const leadAtual = (msg.payload && msg.payload[0]) || {};
const crm = msg.crm || {};
const merged = {
  telefone: crm.telefone,
  nome: crm.nome || leadAtual.nome || null,
  empresa: crm.empresa || leadAtual.empresa || null,
  itens_interesse: crm.itens_interesse || leadAtual.itens_interesse || null,
  estado: crm.estado || leadAtual.estado || null,
  cidade: crm.cidade || leadAtual.cidade || null
};
const completo = Boolean(merged.nome && merged.itens_interesse);
const status = completo ? 'lead_qualificado_bot' : 'dados_incompletos';
flow.set('ctx:' + merged.telefone, merged);
msg.crm = merged;
msg.crm.status = status;
msg.topic = `INSERT INTO leads (telefone, nome, empresa, itens_interesse, estado, cidade, origem, status)
VALUES ($1,$2,$3,$4::jsonb,$5,$6,'whatsapp',$7)
ON CONFLICT (telefone) DO UPDATE SET
nome = EXCLUDED.nome,
empresa = EXCLUDED.empresa,
itens_interesse = EXCLUDED.itens_interesse,
estado = EXCLUDED.estado,
cidade = EXCLUDED.cidade,
status = EXCLUDED.status,
updated_at = now()
RETURNING *`;
msg.payload = [merged.telefone, merged.nome, merged.empresa, JSON.stringify(merged.itens_interesse || []), merged.estado, merged.cidade, status];
return [msg, completo ? null : msg];

msg.topic = 'SELECT id, nome FROM vendedores WHERE ativo = true ORDER BY created_at';
msg.payload = [];
return msg;

const rows = msg.payload || [];
if (!rows.length) {
  node.error('Nenhum vendedor ativo', msg);
  return null;
}
let idx = flow.get('vendedor_rr_idx') || 0;
const vendedor = rows[idx % rows.length];
flow.set('vendedor_rr_idx', (idx + 1) % rows.length);
const leadId = (msg.payload_lead && msg.payload_lead.id) || (msg.crm_lead && msg.crm_lead.id) || (msg.crm && msg.crm.id) || null;
msg.crm_vendedor = vendedor;
msg.topic = `INSERT INTO atendimentos (lead_id, vendedor_id, status, canal, observacoes) VALUES ($1,$2,'transferido_vendedor','whatsapp',$3) RETURNING *`;
msg.payload = [leadId, vendedor.id, 'Auto-roteamento via round-robin'];
return msg;

const total = Number(msg.total || msg.pedido?.total || 0);
if (!(total > 0)) {
  node.error('Total inválido para gerar PIX', msg);
  return null;
}
msg.pix = {
  chave: '02445780012',
  valor: total.toFixed(2),
  descricao: `Pedido ${msg.pedido?.id || ''}`
};
return msg;

const txid = msg.payload?.txid || msg.payload?.id;
const copia = msg.payload?.pix_copia_cola || msg.payload?.copiaecola;
const pedidoId = msg.pedido?.id;
msg.topic = `UPDATE pedidos SET pix_txid=$1, pix_copia_cola=$2, status='aguardando_pagamento', updated_at=now() WHERE id=$3 RETURNING *`;
msg.payload = [txid, copia, pedidoId];
msg.pix = { txid, copia };
return msg;

